(() => {

  const content = $('Get a document1').item.json.body.content;

  const placeholder = $json.imagePlaceholder;

  let foundIndex = -1;

  function search(elements) {

    for (const item of elements) {

      if (item.paragraph?.elements) {

        for (const el of item.paragraph.elements) {

          const text = el.textRun?.content || '';

          if (text.includes(placeholder)) {
            foundIndex = el.startIndex;
            return;
          }
        }
      }

      if (item.table?.tableRows) {

        for (const row of item.table.tableRows) {

          for (const cell of row.tableCells) {

            search(cell.content);

            if (foundIndex !== -1) return;
          }
        }
      }
    }
  }

  search(content);

  return foundIndex;

})()
}}

