// Detecta origem dos dados
const input = $input.first().json;

const veioDoWebhook = !!input.body;

function formatarData(data) {

  if (!data) return '';

  const limpa = data.split('T')[0];

  const [ano, mes, dia] = limpa.split('-');

  return `${dia}/${mes}/${ano}`;
}

// =========================
// Formata endereço ReceitaWS
// =========================
function montarEnderecoReceita(receita) {

  if (!receita) return '';

  const logradouro = receita.logradouro || '';
  const numero = receita.numero || '';
  const complemento = receita.complemento
    ? ' - ' + receita.complemento
    : '';

  const bairro = receita.bairro || '';
  const municipio = receita.municipio || '';

  const uf = (receita.uf || '').toUpperCase();

  const cep = (receita.cep || '')
    .replace(/\D/g, '')
    .replace(/(\d{5})(\d{3})/, '$1-$2');

  const titleCase = (str) =>
    str
      .toLowerCase()
      .replace(/\b[a-zà-ú]/gi, (c) => c.toUpperCase());

  return `${titleCase(logradouro)}, ${numero}${complemento}, ${titleCase(bairro)}, ${titleCase(municipio)}, ${uf}, ${cep}`;
}

// =========================
// Busca endereço via ReceitaWS
// =========================
async function buscarEnderecoPorCNPJ(cnpj) {

  try {

    const cnpjLimpo = cnpj.replace(/\D/g, '');

    const response = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://www.receitaws.com.br/v1/cnpj/${cnpjLimpo}`,
      json: true
    });

    return montarEnderecoReceita(response);

  } catch (e) {

    return '';
  }
}

let output = {};

if (veioDoWebhook) {

  // =========================
  // WEBHOOK / PLATAFORMA
  // =========================

  const body = input.body;

  const placeholders = body.placeholders || {};

  let endereco = placeholders.endereco_condominio || '';

  // Busca via CNPJ se endereço vazio
  if (!endereco && placeholders.numero_cnpj) {

    endereco = await buscarEnderecoPorCNPJ.call(
      this,
      placeholders.numero_cnpj
    );
  }

  output = {

    origem: 'Plataforma',

    id_condomino: body.condomino.id || '',

    numero_bloco: placeholders.numero_bloco || '',

    numero_unidade: placeholders.numero_unidade || '',

    data_infracao: formatarData(placeholders.data_infracao),

    cabecalho_notificacao:
      placeholders.cabecalho_notificacao ||
      `${body.condomino.relacao}: ${body.condomino.nome}`,

    foto_infracao: placeholders.foto_infracao || '',

    id_condominio: body.condominio.id || '',

    nome_condominio: placeholders.nome_condominio || '',

    numero_cnpj: placeholders.numero_cnpj || '',

    nome_sindico: placeholders.nome_sindico
      ? `${placeholders.nome_sindico} - síndico`
      : '',

    assinatura_sindico:
      placeholders.assinatura_sindico || null,

    logo_condominio: placeholders.logo_condominio || '',

    endereco_condominio: endereco,

    infracao: placeholders.infracao || '',

    template_corpo:
      body.template_corpo ||
      '1SGUBZEgYR3wGZkzjYpxCv-QU0t52-AN1vD3YscB5g-Y'
  };

} else {

  // =========================
  // N8N / OUTRO WORKFLOW
  // =========================

  let endereco = input.condominio_endereco || '';

  // Busca via CNPJ se endereço vazio
  if (!endereco && input.condominio_cnpj) {

    endereco = await buscarEnderecoPorCNPJ.call(
      this,
      input.condominio_cnpj
    );
  }

  output = {

    origem: 'N8N',

    id_condomino: input.condomino_id || '',

    numero_bloco: input.condomino_bloco || '',

    numero_unidade: input.condomino_unidade || '',

    data_infracao: formatarData(input.data_infracao),

    cabecalho_notificacao:
      `${input.condomino_relacao || 'Condômino'}: ${input.condomino_nome || ''}`,

    foto_infracao: input.foto_infracao_path || '',

    id_condominio: input.condominio_id || '',

    nome_condominio: input.condominio_nome || '',

    numero_cnpj: input.condominio_cnpj || '',

    nome_sindico: input.condominio_sindico_nome
      ? `${input.condominio_sindico_nome} - síndico`
      : '',

    assinatura_sindico:
      input.condominio_sindico_assinatura || null,

    logo_condominio: input.condominio_logo_url || '',

    endereco_condominio: endereco,

    infracao: input.infracao || '',

    template_corpo:
      '1SGUBZEgYR3wGZkzjYpxCv-QU0t52-AN1vD3YscB5g-Y'
  };
}

return [
  {
    json: output
  }
];

